import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';

export const dynamic = 'force-dynamic';

async function syncLatestCatalog() {
  'use server';
  revalidateTag('products');
}

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ padding: 24, fontFamily: 'system-ui, sans-serif' }}>
      <h1>Product Catalog</h1>
      <p>Browse the latest catalog data without forcing every request to recompute it.</p>

      <form action={syncLatestCatalog} style={{ margin: '16px 0 24px' }}>
        <button type="submit">Sync latest catalog</button>
      </form>

      <table cellPadding={8} style={{ borderCollapse: 'collapse', minWidth: 420 }}>
        <thead>
          <tr>
            <th align="left">ID</th>
            <th align="left">Name</th>
            <th align="left">Price</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id}>
              <td>{product.id}</td>
              <td>{product.name}</td>
              <td>${product.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}

const products = [
  { id: 1, name: 'Laptop', price: 999 },
  { id: 2, name: 'Phone', price: 699 },
  { id: 3, name: 'Tablet', price: 499 },
  { id: 4, name: 'Headphones', price: 199 },
  { id: 5, name: 'Watch', price: 299 },
];

export async function getAllProducts() {
  // Simulate database delay
  await new Promise((resolve) => setTimeout(resolve, 100));

  return products;
}

import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';

export const dynamic = 'force-dynamic';

async function syncLatestCatalog(formData: FormData) {
  'use server';
  void formData;
  revalidateTag('products', 'max');
}

export default async function Page() {
  const products = await getAllProducts();

  return (
    <main style={{ padding: 24, fontFamily: 'system-ui, sans-serif' }}>
      <h1>Product Catalog</h1>
      <p>Browse the latest catalog data without forcing every request to recompute it.</p>

      <form action={syncLatestCatalog} style={{ margin: '16px 0 24px' }}>
        <button type="submit">Sync latest catalog</button>
      </form>

      <table cellPadding={8} style={{ borderCollapse: 'collapse', minWidth: 420 }}>
        <thead>
          <tr>
            <th align="left">ID</th>
            <th align="left">Name</th>
            <th align="left">Price</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id}>
              <td>{product.id}</td>
              <td>{product.name}</td>
              <td>${product.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
